// ASP.NET Core: configure WS-Federation middleware (Microsoft.AspNetCore.Authentication.WsFederation)
// Install: dotnet add package Microsoft.AspNetCore.Authentication.WsFederation

using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Authentication.WsFederation;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddAuthentication(options =>
{
    options.DefaultScheme          = CookieAuthenticationDefaults.AuthenticationScheme;
    options.DefaultChallengeScheme = WsFederationDefaults.AuthenticationScheme;
})
.AddCookie()
.AddWsFederation(options =>
{
    string tenantId = builder.Configuration["Entra:TenantId"]!;

    // The URL of Entra's WS-Federation endpoint
    options.MetadataAddress =
        $"https://login.microsoftonline.com/{tenantId}/federationmetadata/2007-06/federationmetadata.xml";

    // wtrealm: identifies this Relying Party to Entra
    // Must match the Identifier URI in the Entra app registration
    options.Wtrealm = builder.Configuration["Entra:WtRealm"]!;

    // Optional: redirect to a specific URL after sign-in
    options.Wreply = "https://myapp.example.com/signin-wsfed";

    // Save the token for downstream use (e.g., pass to on-prem WCF service)
    options.SaveTokens = true;

    // Claims from the SAML assertion inside the RSTR become ClaimsPrincipal
    options.TokenValidationParameters = new()
    {
        ValidAudience = builder.Configuration["Entra:WtRealm"],
    };
})
;

var app = builder.Build();
app.UseAuthentication();
app.UseAuthorization();

// Trigger sign-in: return a 401/403 or call ChallengeAsync
app.MapGet("/profile", async (HttpContext ctx) =>
{
    if (!ctx.User.Identity?.IsAuthenticated ?? true)
        return Results.Challenge();

    var name  = ctx.User.FindFirst(ClaimTypes.Name)?.Value;
    var email = ctx.User.FindFirst(ClaimTypes.Email)?.Value;
    return Results.Ok(new { name, email });
});

// Sign-out: clear cookie and redirect to Entra WS-Federation sign-out
app.MapGet("/logout", async (HttpContext ctx) =>
{
    await ctx.SignOutAsync(CookieAuthenticationDefaults.AuthenticationScheme);
    await ctx.SignOutAsync(WsFederationDefaults.AuthenticationScheme);
});

// WS-Trust active profile: thick client (WPF, WCF, console) obtains token directly
// Used by on-premises WCF services and legacy .NET clients
// The client POSTs credentials directly to the STS SOAP endpoint

using System.Net;
using System.ServiceModel;
using System.ServiceModel.Security;

// Option 1: Use Microsoft.Identity.Client (MSAL) — preferred even for WCF
// MSAL's AcquireTokenByUsernamePassword uses WS-Trust under the hood for legacy scenarios
using Microsoft.Identity.Client;

var app = PublicClientApplicationBuilder.Create("<client-id>")
    .WithAuthority(AzureCloudInstance.AzurePublic, "<tenant-id>")
    .Build();

// Acquire token using username/password (uses WS-Trust internally for federated domains)
var result = await app.AcquireTokenByUsernamePassword(
    scopes:   new[] { "https://graph.microsoft.com/User.Read" },
    username: "alice@contoso.com",
    password: new System.Net.NetworkCredential("", "<password>").SecurePassword
).ExecuteAsync();

Console.WriteLine($"Token obtained, expires: {result.ExpiresOn}");

// NOTE: Username/Password flow (ROPC) is deprecated for new scenarios.
// It cannot satisfy MFA and bypasses Conditional Access.
// Use Device Code or Interactive auth for user-facing scenarios instead.
// Reserve WS-Trust/ROPC only for migration from legacy WCF services where
// interactive authentication is not possible.

# Migrating from WS-Federation to OIDC: assessment and plan

# Step 1: Inventory apps using WS-Federation
# In Entra admin center: Enterprise applications → filter by 'Single sign-on: WS-Fed'
# Via Graph:
import requests

def get_wsfed_apps(access_token: str) -> list:
    headers = {'Authorization': f'Bearer {access_token}'}
    # Filter service principals by preferredSingleSignOnMode
    url = ('https://graph.microsoft.com/v1.0/servicePrincipals'
           '?$filter=preferredSingleSignOnMode eq \"wsFed\"'
           '&$select=displayName,appId,preferredSingleSignOnMode')
    resp = requests.get(url, headers=headers).json()
    return resp.get('value', [])

# Step 2: Assess migration effort per app
# - ASP.NET 4.x with WIF: update to Microsoft.Identity.Web (OIDC)
# - ASP.NET Core with WsFederation middleware: swap for AddOpenIdConnect
# - Third-party SaaS apps: check if vendor supports OIDC (most modern ones do)

# Step 3: For ASP.NET Core — swap WsFederation for OIDC middleware
# Before (WS-Fed):
