#     options.ClientId = '<client-id>';
#     options.ClientSecret = '<client-secret>';
#     options.ResponseType = OpenIdConnectResponseType.Code;
# });

# Step 4: Update the app registration in Entra
# Change preferredSingleSignOnMode from 'wsFed' to 'oidc'
# Add redirect URI for OIDC callback
# Remove wtrealm / wsFederation config

// WS-Federation claims arrive as System.Security.Claims.Claim objects in ClaimsPrincipal
// Entra ID uses WS-Federation-era claim type URIs

// Common claim URIs in WS-Federation tokens from Entra:
// http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name           → display name
// http://schemas.xmlsoap.org/ws/2005/05/identity/claims/upn            → UPN
// http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress   → email
// http://schemas.microsoft.com/identity/claims/objectidentifier         → OID (stable)
// http://schemas.microsoft.com/identity/claims/tenantid                 → tenant ID
// http://schemas.microsoft.com/claims/authnmethodsreferences            → MFA methods

// In ASP.NET Core, access claims from HttpContext.User:
app.MapGet("/me", (HttpContext ctx) =>
{
    var user = ctx.User;
    return new
    {
        Name    = user.FindFirst("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name")?.Value,
        Email   = user.FindFirst("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress")?.Value,
        Oid     = user.FindFirst("http://schemas.microsoft.com/identity/claims/objectidentifier")?.Value,
        TenantId = user.FindFirst("http://schemas.microsoft.com/identity/claims/tenantid")?.Value,
        // .NET's built-in ClaimTypes aliases map the common claims:
        NameAlt = user.FindFirst(System.Security.Claims.ClaimTypes.Name)?.Value,
        EmailAlt = user.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value,
    };
}).RequireAuthorization();

// Map group claims to roles for authorization:
